using UnityEngine;

/// <summary>
/// Base comum para os controllers específicos de cada um dos 8 bosses do GDD
/// 12.3 (Guardião do Ferro Enraizado, Sol de Plástico, Garganta do Fogo,
/// Gigante do Degelo, Maré de Rede, Sino do Ruído, A Mão que Fere, A Mente que
/// Mata). Item da auditoria: "Bosses têm apenas estrutura genérica" —
/// EnemyMultiPartBoss/EnemyHealth/EnemyAttackController já dão a base
/// (vida, partes destrutíveis, janela de vulnerabilidade, ataques), mas faltava
/// um ponto de extensão próprio para CADA boss.
///
/// Esta classe NÃO implementa nenhum moveset — apenas liga os sistemas
/// genéricos já existentes (BossHealthBarUI, AudioManager, EnemyMultiPartBoss)
/// e expõe hooks virtuais que cada subclasse (ver ficheiros Boss_*.cs nesta
/// pasta) deve preencher com a sua mecânica própria (fases, ataques especiais,
/// janelas de vulnerabilidade específicas, VFX, etc — trabalho futuro,
/// propositadamente fora do âmbito desta preparação).
///
/// Colocar no corpo principal do boss (mesmo GameObject que EnemyController +
/// EnemyHealth). EnemyMultiPartBoss é opcional (bosses sem partes
/// destrutíveis próprias podem não o ter).
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController), typeof(EnemyHealth))]
public abstract class BossController : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("Identificador deste boss (chave estável — usar em WorldData.bossId, condições, saves, etc).")]
    public string bossId;

    [Tooltip("Nome mostrado na BossHealthBarUI ao iniciar o combate.")]
    public string displayName;

    [Header("Música (opcional)")]
    [Tooltip("BGM tocada (AudioManager.PlayBGM) ao iniciar o combate via StartBossFight(). Deixar vazio se a música já for tratada por Action_PlayBGM no evento de entrada na arena.")]
    public AudioClip bossBgm;

    /// <summary>EnemyController do corpo principal do boss.</summary>
    protected EnemyController Controller { get; private set; }

    /// <summary>EnemyHealth do corpo principal do boss.</summary>
    protected EnemyHealth Health { get; private set; }

    /// <summary>EnemyMultiPartBoss (partes destrutíveis/fases), se existir neste boss.</summary>
    protected EnemyMultiPartBoss MultiPart { get; private set; }

    private bool _fightStarted;
    private bool _defeated;

    /// <summary>True depois de StartBossFight ter sido chamado (combate em curso ou terminado).</summary>
    public bool FightStarted => _fightStarted;

    /// <summary>True depois do boss morrer/desactivar (OnDefeated já disparado).</summary>
    public bool Defeated => _defeated;

    protected virtual void Awake()
    {
        Controller = GetComponent<EnemyController>();
        Health = GetComponent<EnemyHealth>();
        MultiPart = GetComponent<EnemyMultiPartBoss>();
    }

    protected virtual void OnEnable()
    {
        if (Health != null) Health.OnHealthChanged += HandleHealthChanged;
        if (Controller != null) Controller.OnStateChanged += HandleStateChanged;

        if (MultiPart != null)
        {
            MultiPart.onPartDefeated.AddListener(HandlePartDefeated);
            MultiPart.onAllPartsDefeated.AddListener(HandleAllPartsDefeated);
        }
    }

    protected virtual void OnDisable()
    {
        if (Health != null) Health.OnHealthChanged -= HandleHealthChanged;
        if (Controller != null) Controller.OnStateChanged -= HandleStateChanged;

        if (MultiPart != null)
        {
            MultiPart.onPartDefeated.RemoveListener(HandlePartDefeated);
            MultiPart.onAllPartsDefeated.RemoveListener(HandleAllPartsDefeated);
        }
    }

    /// <summary>
    /// Chamar ao entrar na arena do boss (trigger dedicado, ou NpcAction no
    /// início do encontro): mostra a BossHealthBarUI, toca "bossBgm" (se
    /// definida) e dispara <see cref="OnIntroStart"/>. Sem efeito se já tiver
    /// sido chamado.
    /// </summary>
    public void StartBossFight()
    {
        if (_fightStarted) return;
        _fightStarted = true;

        if (Health != null)
            BossHealthBarUI.Instance?.Show(string.IsNullOrEmpty(displayName) ? name : displayName, Health.MaxHealth);

        if (bossBgm != null)
            AudioManager.Instance?.PlayBGM(bossBgm);

        OnIntroStart();
    }

    private void HandleHealthChanged(int current, int max)
    {
        BossHealthBarUI.Instance?.SetHealth(current);
    }

    private void HandleStateChanged(EnemyState oldState, EnemyState newState)
    {
        if (_defeated) return;
        if (newState != EnemyState.Morto && newState != EnemyState.Desactivado) return;

        _defeated = true;
        BossHealthBarUI.Instance?.Hide();
        OnDefeated();
    }

    private void HandlePartDefeated(int alivePartCount)
    {
        OnPhaseChanged(MultiPart != null ? MultiPart.DefeatedPartCount : 0, alivePartCount);
    }

    private void HandleAllPartsDefeated()
    {
        OnAllPartsDefeated();
    }

    // ==================== Hooks (preenchidos por cada Boss_*.cs) ====================

    /// <summary>
    /// Início do combate (StartBossFight) — câmara, diálogo de abertura,
    /// activar partes/ataques iniciais, etc. Sem implementação por omissão.
    /// </summary>
    protected virtual void OnIntroStart() { }

    /// <summary>
    /// Uma parte destrutível foi derrotada (EnemyMultiPartBoss.onPartDefeated)
    /// — "defeatedParts"/"aliveParts" referem-se ao total de partes
    /// registadas em EnemyMultiPartBoss.parts. Usar para avançar de fase,
    /// trocar ataques disponíveis, mudar VFX/Animator, etc.
    /// </summary>
    protected virtual void OnPhaseChanged(int defeatedParts, int aliveParts) { }

    /// <summary>
    /// Todas as partes destrutíveis caíram (EnemyMultiPartBoss.onAllPartsDefeated)
    /// — geralmente a última fase / abertura da janela de vulnerabilidade total.
    /// </summary>
    protected virtual void OnAllPartsDefeated() { }

    /// <summary>
    /// O corpo principal do boss morreu/desactivou — sequência de derrota
    /// (drops, NpcAction de Action_SetBossDefeated, animação final, etc, fora
    /// do âmbito desta preparação).
    /// </summary>
    protected virtual void OnDefeated() { }
}
